// 2. Presale Contract
contract TokenPresale {
    address public tokenAddress;
    mapping(address => bool) public isWhitelisted;
    uint256 public price; // e.g., 1000 tokens per 1 ETH
    uint256 public hardCap;
    uint256 public raised;

    // Only whitelisted addresses can buy
    function buyTokens() external payable {
        require(isWhitelisted[msg.sender], "Not whitelisted");
        require(block.timestamp >= startTime, "Sale not started");
        require(raised + msg.value <= hardCap, "Hard cap reached");

        uint256 tokensToMint = (msg.value * price);

        // Transfer tokens from this contract to the buyer
        IERC20(tokenAddress).transfer(msg.sender, tokensToMint);

        raised += msg.value;
    }

    // Function to add investors to whitelist (Owner only)
    function addToWhitelist(address investor) external onlyOwner {
        isWhitelisted[investor] = true;
    }

    // Function to finalize and move funds to Launchpad/Liquidity
    function finalizeSale() external onlyOwner {
        // Logic to check soft cap, refund if failed, 
        // or transfer ETH to Liquidity Provider if successful.
    }
}
