// Define a "Duck" interface
interface Duck {
  quack(): void;
  fly(): void;
}

// A function expecting a Duck
function letItFly(duck: Duck) {
  duck.fly();
}

// Object A: Explicitly implements the interface
const realDuck: Duck = {
  quack: () => console.log("Quack"),
  fly: () => console.log("Flying")
};

// Object B: Does NOT declare it implements Duck, 
// but has the same shape (Duck Typing in action)
const rubberDuck = {
  quack: () => console.log("Squeak"),
  fly: () => console.log("Floating")
};

// TypeScript accepts rubberDuck because it "looks like a duck"
letItFly(realDuck);   // ✅ OK
letItFly(rubberDuck); // ✅ OK (Structural Typing)

// This would fail because it's missing 'fly'
letItFly({ quack: () => {} }); // ❌ Error: Property 'fly' is missing
